  2→import { randomUUID } from "node:crypto";
  3→import { RecordId, type Surreal } from "surrealdb";
  4→import { collectSseEvents, createTestUser, fetchJson, type TestUser, setupAcceptanceSuite } from "../acceptance-test-kit";
