 21→const getRuntime = setupAcceptanceSuite("subagent_traces");
 22→
 23→async function createOnboardedWorkspaceWithProject(
 24→  baseUrl: string,
 25→  surreal: Surreal,
 26→  user: TestUser,
 27→): Promise<{ workspaceId: string; conversationId: string }> {
 28→  const workspace = await fetchJson<{ workspaceId: string; conversationId: string }>(`${baseUrl}/api/workspaces`, {
 29→    method: "POST",
 30→    headers: { "Content-Type": "application/json", ...user.headers },
 31→    body: JSON.stringify({ name: `Traces Smoke ${Date.now()}` }),
 32→  });
 33→
 34→  const workspaceRecord = new RecordId("workspace", workspace.workspaceId);
 35→  await surreal.update(workspaceRecord).merge({
 36→    onboarding_complete: true,
 37→    onboarding_summary_pending: false,
 38→    onboarding_completed_at: new Date(),
 39→  });
 40→
 41→  // Seed a project so the PM agent has context to work with
 42→  const projectRecord = new RecordId("project", randomUUID());
 43→  await surreal.create(projectRecord).content({
 44→    name: "DabDash",
 45→    status: "active",
 46→    workspace: workspaceRecord,
 47→    created_at: new Date(),
 48→    updated_at: new Date(),
 49→  });
 50→  await surreal
 51→    .relate(workspaceRecord, new RecordId("has_project", randomUUID()), projectRecord, {
 52→      added_at: new Date(),
 53→    })
 54→    .output("after");
 55→
 56→  return workspace;
 57→}
 58→
 59→describe("subagent trace persistence", () => {
 60→  it("PM agent traces are persisted and loaded via conversation endpoint", async () => {
 61→    const { baseUrl, surreal } = getRuntime();
 62→    const user = await createTestUser(baseUrl, "traces-1");
 63→    const workspace = await createOnboardedWorkspaceWithProject(baseUrl, surreal, user);
 64→
 65→    // Send a message that should trigger the PM agent (task/feature planning)
 66→    const message = await fetchJson<ChatMessageResponse>(`${baseUrl}/api/chat/messages`, {
 67→      method: "POST",
 68→      headers: { "Content-Type": "application/json", ...user.headers },
 69→      body: JSON.stringify({
 70→        clientMessageId: randomUUID(),
 71→        workspaceId: workspace.workspaceId,
 72→        conversationId: workspace.conversationId,
 73→        text: "Plan work for DabDash: we need a dashboard with real-time order count, revenue stats, and low stock alerts.",
 74→      }),
 75→    });
 76→
 77→    // Wait for streaming to complete
 78→    const events = await collectSseEvents<StreamEvent>(`${baseUrl}${message.streamUrl}`, 120_000);
 79→    expect(events.some((e) => e.type === "done")).toBe(true);
 80→
 81→    // Verify traces persisted on the assistant message in DB
 82→    const assistantMessageRecord = new RecordId("message", message.messageId);
 83→    const [messageRows] = await surreal
 84→      .query<[Array<{ id: RecordId<"message", string>; subagent_traces?: SubagentTrace[] }>]>(
 85→        "SELECT id, subagent_traces FROM message WHERE id = $msg;",
 86→        { msg: assistantMessageRecord },
 87→      )
 88→      .collect<[Array<{ id: RecordId<"message", string>; subagent_traces?: SubagentTrace[] }>]>();
 89→
 90→    expect(messageRows.length).toBe(1);
 91→    const assistantMsg = messageRows[0]!;
 92→
 93→    // The chat agent should have invoked the PM agent for this planning request.
 94→    // If it did, traces should be present. If not (LLM non-determinism), skip trace assertions.
 95→    if (!assistantMsg.subagent_traces || assistantMsg.subagent_traces.length === 0) {
 96→      console.warn("PM agent was not invoked — skipping trace structure assertions (LLM non-determinism)");
 97→      return;
 98→    }
 99→
