  1→import { randomUUID } from "node:crypto";
  2→import { RecordId, type Surreal } from "surrealdb";
  3→import type { SubagentTrace, SubagentTraceStep } from "../../../../app/src/shared/contracts";
  4→import { createTestUser, fetchJson, type TestUser } from "../../acceptance-test-kit";
  5→
  6→// ---------------------------------------------------------------------------
  7→// Fixture types
  8→// ---------------------------------------------------------------------------
  9→
 10→export type TraceFixture = {
 11→  rootTraceId: string;
 12→  childTraceIds: string[];
 13→  spawnsEdgeId: string;
 14→};
 15→
 16→export type SeededConversation = {
 17→  workspaceId: string;
 18→  workspaceRecord: RecordId<"workspace", string>;
 19→  conversationId: string;
 20→  conversationRecord: RecordId<"conversation", string>;
 21→  identityRecord: RecordId<"identity", string>;
 22→};
 23→
 24→// ---------------------------------------------------------------------------
 25→// Workspace + conversation scaffolding
 26→// ---------------------------------------------------------------------------
 27→
 28→export async function seedConversation(
 29→  baseUrl: string,
 30→  surreal: Surreal,
 31→  user: TestUser,
 32→  suffix: string,
 33→): Promise<SeededConversation> {
 34→  const workspace = await fetchJson<{ workspaceId: string; conversationId: string }>(
 35→    `${baseUrl}/api/workspaces`,
 36→    {
 37→      method: "POST",
 38→      headers: { "Content-Type": "application/json", ...user.headers },
 39→      body: JSON.stringify({ name: `TraceMigration ${suffix} ${randomUUID().slice(0, 8)}` }),
 40→    },
 41→  );
 42→
 43→  const workspaceRecord = new RecordId("workspace", workspace.workspaceId);
 44→
 45→  // Mark onboarding complete so bootstrap returns full messages
 46→  await surreal.update(workspaceRecord).merge({
 47→    onboarding_complete: true,
 48→    onboarding_summary_pending: false,
 49→    onboarding_completed_at: new Date(),
 50→  });
 51→
 52→  // Create an identity record (required for trace.actor)
 53→  const identityId = randomUUID();
 54→  const identityRecord = new RecordId("identity", identityId);
 55→  await surreal.create(identityRecord).content({
 56→    kind: "human",
 57→    label: `test-user-${suffix}`,
 58→    workspace: workspaceRecord,
 59→    created_at: new Date(),
 60→  });
 61→
 62→  return {
 63→    workspaceId: workspace.workspaceId,
 64→    workspaceRecord,
 65→    conversationId: workspace.conversationId,
 66→    conversationRecord: new RecordId("conversation", workspace.conversationId),
 67→    identityRecord,
 68→  };
 69→}
 70→
 71→// ---------------------------------------------------------------------------
 72→// Message seeding
 73→// ---------------------------------------------------------------------------
 74→
 75→export async function seedAssistantMessage(
 76→  surreal: Surreal,
 77→  conversationRecord: RecordId<"conversation", string>,
 78→  text: string,
 79→  createdAt?: Date,
 80→): Promise<RecordId<"message", string>> {
 81→  const messageRecord = new RecordId("message", randomUUID());
 82→  await surreal.create(messageRecord).content({
 83→    conversation: conversationRecord,
 84→    role: "assistant",
 85→    text,
 86→    createdAt: createdAt ?? new Date(),
 87→  });
 88→  return messageRecord;
 89→}
 90→
 91→export async function seedUserMessage(
 92→  surreal: Surreal,
 93→  conversationRecord: RecordId<"conversation", string>,
 94→  text: string,
 95→  createdAt?: Date,
 96→): Promise<RecordId<"message", string>> {
 97→  const messageRecord = new RecordId("message", randomUUID());
 98→  await surreal.create(messageRecord).content({
 99→    conversation: conversationRecord,
100→    role: "user",
101→    text,
102→    createdAt: createdAt ?? new Date(),
103→  });
104→  return messageRecord;
105→}
106→
107→// ---------------------------------------------------------------------------
108→// Trace seeding (simulates the normalized write path)
109→// ---------------------------------------------------------------------------
110→
111→/**
112→ * Seed a full trace tree for a message: root trace + child traces + spawns edge.
113→ * This simulates what chat-route.ts onFinish will do after migration.
114→ */
115→export async function seedTraceForMessage(
116→  surreal: Surreal,
117→  messageRecord: RecordId<"message", string>,
118→  workspaceRecord: RecordId<"workspace", string>,
119→  identityRecord: RecordId<"identity", string>,
120→  trace: SubagentTrace,
121→): Promise<TraceFixture> {
122→  const rootTraceId = randomUUID();
123→  const rootTraceRecord = new RecordId("trace", rootTraceId);
124→  const now = new Date();
125→
126→  // Create root trace record (type: "subagent_spawn")
127→  await surreal.create(rootTraceRecord).content({
128→    type: "subagent_spawn",
129→    actor: identityRecord,
130→    workspace: workspaceRecord,
131→    tool_name: "invoke_pm_agent",
132→    input: { intent: trace.intent, agentId: trace.agentId },
133→    duration_ms: trace.totalDurationMs,
134→    created_at: now,
135→  });
136→
137→  // Create child trace records for each step
138→  const childTraceIds: string[] = [];
139→  for (const step of trace.steps) {
140→    const childId = randomUUID();
141→    const childRecord = new RecordId("trace", childId);
142→    childTraceIds.push(childId);
143→
144→    if (step.type === "tool_call") {
145→      await surreal.create(childRecord).content({
146→        type: "tool_call",
147→        actor: identityRecord,
148→        workspace: workspaceRecord,
149→        parent_trace: rootTraceRecord,
150→        tool_name: step.toolName,
151→        input: step.argsJson ? JSON.parse(step.argsJson) : undefined,
152→        output: step.resultJson ? JSON.parse(step.resultJson) : undefined,
153→        duration_ms: step.durationMs,
154→        created_at: now,
155→      });
156→    } else {
157→      // type: "text" → stored as type: "message" in trace table
158→      await surreal.create(childRecord).content({
159→        type: "message",
160→        actor: identityRecord,
161→        workspace: workspaceRecord,
162→        parent_trace: rootTraceRecord,
163→        input: { text: step.text },
164→        created_at: now,
165→      });
166→    }
167→  }
168→
169→  // Create spawns edge: message ->spawns-> root trace
170→  const spawnsId = randomUUID();
171→  await surreal
172→    .relate(messageRecord, new RecordId("spawns", spawnsId), rootTraceRecord, {})
173→    .output("after");
174→
175→  return { rootTraceId, childTraceIds, spawnsEdgeId: spawnsId };
176→}
177→
178→// ---------------------------------------------------------------------------
179→// Sample trace fixtures
180→// ---------------------------------------------------------------------------
181→
182→export function makeSampleTrace(overrides?: Partial<SubagentTrace>): SubagentTrace {
183→  return {
184→    agentId: "pm_agent",
185→    intent: "plan_work",
186→    totalDurationMs: 1500,
187→    steps: [
188→      {
189→        type: "tool_call",
190→        toolName: "search_entities",
191→        argsJson: JSON.stringify({ query: "dashboard features" }),
192→        resultJson: JSON.stringify({ results: [] }),
193→        durationMs: 200,
194→      },
195→      {
196→        type: "tool_call",
197→        toolName: "create_work_item",
198→        argsJson: JSON.stringify({ title: "Build dashboard", kind: "task" }),
199→        resultJson: JSON.stringify({ id: "task:abc123" }),
200→        durationMs: 300,
201→      },
202→      {
203→        type: "text",
204→        text: "I've created a task for the dashboard feature.",
205→      },
206→    ],
207→    ...overrides,
208→  };
209→}
210→
211→export function makeSampleTraceMinimal(): SubagentTrace {
212→  return {
213→    agentId: "pm_agent",
214→    intent: "check_status",
215→    totalDurationMs: 400,
216→    steps: [
217→      {
218→        type: "tool_call",
219→        toolName: "get_project_status",
220→        argsJson: JSON.stringify({ projectId: "proj-1" }),
221→        resultJson: JSON.stringify({ status: "active", taskCount: 3 }),
222→        durationMs: 400,
223→      },
224→    ],
225→  };
226→}
227→
228→// ---------------------------------------------------------------------------
229→// Assertion helpers
230→// ---------------------------------------------------------------------------
231→
232→/**
233→ * Query trace records linked to a message via spawns edge.
234→ */
235→export async function querySpawnedTraces(
236→  surreal: Surreal,
237→  messageRecord: RecordId<"message", string>,
238→): Promise<Array<{ id: RecordId; type: string; parent_trace?: RecordId }>> {
239→  const [rows] = await surreal
240→    .query<[Array<{ id: RecordId; type: string; parent_trace?: RecordId }>]>(
241→      "SELECT id, type, parent_trace FROM trace WHERE <-spawns<-message CONTAINS $msg;",
242→      { msg: messageRecord },
243→    )
244→    .collect<[Array<{ id: RecordId; type: string; parent_trace?: RecordId }>]>();
245→  return rows;
246→}
247→
248→/**
249→ * Query all child traces for a root trace.
