420→/**
421→ * Create a test user with DPoP-bound token for MCP endpoints.
422→ * Generates key pair, creates identity, seeds broad-access intent, acquires token.
423→ */
424→export async function createTestUserWithMcp(
425→  baseUrl: string,
426→  surreal: Surreal,
427→  suffix: string,
428→  options?: { workspaceId?: string },
429→): Promise<TestUserWithMcp> {
430→  const user = await createTestUser(baseUrl, suffix);
431→
432→  // Generate DPoP key pair
433→  const keyPair = await generateDPoPKeyPair();
434→
435→  // Use provided workspace or create a new one for this test identity
436→  const workspaceId = options?.workspaceId ?? `test-workspace-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
437→  const workspaceRecord = new RecordId("workspace", workspaceId);
438→  if (!options?.workspaceId) {
439→    await surreal.query(`CREATE $workspace CONTENT $content;`, {
440→      workspace: workspaceRecord,
441→      content: {
442→        name: `Test Workspace ${suffix}`,
443→        status: "active",
444→        onboarding_complete: true,
445→        onboarding_turn_count: 0,
446→        onboarding_summary_pending: false,
447→        onboarding_started_at: new Date(),
448→        created_at: new Date(),
449→      },
450→    });
451→  }
452→
453→  // Create identity record for this user
454→  const identityId = `test-identity-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
455→  const identityRecord = new RecordId("identity", identityId);
456→
457→  await surreal.query(`CREATE $identity CONTENT $content;`, {
458→    identity: identityRecord,
459→    content: {
460→      name: `Test User ${suffix}`,
461→      type: "agent",
462→      workspace: workspaceRecord,
463→      identity_status: "active",
464→      created_at: new Date(),
465→    },
466→  });
467→
468→  // Create member_of edge linking identity to workspace (required by DPoP middleware workspace lookup)
469→  await surreal.query(`RELATE $identity->member_of->$workspace SET added_at = time::now();`, {
470→    identity: identityRecord,
471→    workspace: workspaceRecord,
472→  });
473→
474→  // Seed a broad-access authorized intent covering all MCP operations
475→  const broadActions = [
476→    { type: "brain_action", action: "read", resource: "workspace" },
477→    { type: "brain_action", action: "read", resource: "project" },
478→    { type: "brain_action", action: "read", resource: "task" },
479→    { type: "brain_action", action: "read", resource: "decision" },
480→    { type: "brain_action", action: "read", resource: "constraint" },
481→    { type: "brain_action", action: "read", resource: "change_log" },
482→    { type: "brain_action", action: "read", resource: "entity" },
483→    { type: "brain_action", action: "read", resource: "suggestion" },
484→    { type: "brain_action", action: "read", resource: "intent" },
485→    { type: "brain_action", action: "reason", resource: "decision" },
486→    { type: "brain_action", action: "reason", resource: "constraint" },
487→    { type: "brain_action", action: "reason", resource: "commit" },
488→    { type: "brain_action", action: "create", resource: "decision" },
489→    { type: "brain_action", action: "create", resource: "question" },
490→    { type: "brain_action", action: "create", resource: "task" },
491→    { type: "brain_action", action: "create", resource: "note" },
492→    { type: "brain_action", action: "create", resource: "observation" },
493→    { type: "brain_action", action: "create", resource: "suggestion" },
494→    { type: "brain_action", action: "create", resource: "session" },
495→    { type: "brain_action", action: "create", resource: "commit" },
496→    { type: "brain_action", action: "create", resource: "intent" },
497→    { type: "brain_action", action: "update", resource: "task" },
498→    { type: "brain_action", action: "update", resource: "session" },
499→    { type: "brain_action", action: "update", resource: "suggestion" },
500→    { type: "brain_action", action: "submit", resource: "intent" },
501→  ];
502→
503→  const intentId = `test-intent-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
504→  const intentRecord = new RecordId("intent", intentId);
505→  const traceRecord = new RecordId("trace", `trace-${intentId}`);
506→
507→  await surreal.query(`CREATE $trace CONTENT $traceContent;`, {
508→    trace: traceRecord,
509→    traceContent: { type: "intent_submission", actor: identityRecord, workspace: workspaceRecord, created_at: new Date() },
510→  });
511→
512→  await surreal.query(`CREATE $intent CONTENT $content;`, {
513→    intent: intentRecord,
514→    content: {
515→      goal: "Broad test access",
516→      reasoning: "Pre-authorized for acceptance testing",
517→      status: "authorized",
518→      priority: 50,
519→      authorization_details: broadActions,
520→      dpop_jwk_thumbprint: keyPair.thumbprint,
521→      action_spec: { provider: "test", action: "broad_access", params: {} },
522→      trace_id: traceRecord,
523→      requester: identityRecord,
524→      workspace: workspaceRecord,
525→      evaluation: {
526→        decision: "APPROVE",
527→        risk_score: 0,
528→        reason: "Pre-authorized for testing",
529→        evaluated_at: new Date(),
530→        policy_only: true,
531→      },
532→      created_at: new Date(),
533→    },
534→  });
535→
536→  // Request DPoP-bound access token from Custom AS
537→  const tokenUri = `${baseUrl}/api/auth/token`;
538→  const dpopProof = await createDPoPProof(keyPair, "POST", tokenUri);
539→
540→  const tokenRes = await fetch(tokenUri, {
541→    method: "POST",
542→    headers: {
543→      "Content-Type": "application/json",
544→      DPoP: dpopProof,
545→    },
546→    body: JSON.stringify({
547→      grant_type: "urn:brain:intent-authorization",
548→      intent_id: intentId,
549→      authorization_details: broadActions,
550→    }),
551→  });
552→
553→  if (!tokenRes.ok) {
554→    const body = await tokenRes.text();
555→    throw new Error(`DPoP token acquisition failed (${tokenRes.status}): ${body}`);
556→  }
557→
558→  const { access_token } = (await tokenRes.json()) as { access_token: string };
559→
560→  const mcpFetch = async (path: string, options?: { method?: string; body?: unknown }): Promise<Response> => {
561→    const method = options?.method ?? "POST";
562→    const requestUri = `${baseUrl}${path}`;
563→    const proof = await createDPoPProof(keyPair, method, requestUri);
564→
565→    return fetch(requestUri, {
566→      method,
567→      headers: {
568→        "Content-Type": "application/json",
569→        Authorization: `DPoP ${access_token}`,
570→        DPoP: proof,
571→      },
572→      body: options?.body !== undefined ? JSON.stringify(options.body) : JSON.stringify({}),
573→    });
574→  };
575→
576→  return {
577→    ...user,
578→    mcpHeaders: { Authorization: `DPoP ${access_token}` },
579→    mcpFetch,
580→    accessToken: access_token,
581→    keyPair,
582→    workspaceId,
583→    identityId,
584→  };
585→}
