587→// ---------------------------------------------------------------------------
588→// DPoP Helpers
589→// ---------------------------------------------------------------------------
590→
591→async function generateDPoPKeyPair(): Promise<DPoPKeyPair> {
592→  const { publicKey, privateKey } = await crypto.subtle.generateKey(
593→    { name: "ECDSA", namedCurve: "P-256" },
594→    true,
595→    ["sign", "verify"],
596→  );
597→
598→  const publicJwk = await crypto.subtle.exportKey("jwk", publicKey);
599→  const thumbprint = await computeDPoPThumbprint(publicJwk);
600→
601→  return { privateKey, publicKey, publicJwk, thumbprint };
602→}
603→
604→async function computeDPoPThumbprint(publicJwk: JsonWebKey): Promise<string> {
605→  const thumbprintInput = JSON.stringify({
606→    crv: publicJwk.crv,
607→    kty: publicJwk.kty,
608→    x: publicJwk.x,
609→    y: publicJwk.y,
610→  });
611→
612→  const hashBuffer = await crypto.subtle.digest(
613→    "SHA-256",
614→    new TextEncoder().encode(thumbprintInput),
615→  );
616→
617→  return base64urlBytes(new Uint8Array(hashBuffer));
618→}
619→
620→async function createDPoPProof(
621→  keyPair: DPoPKeyPair,
622→  method: string,
623→  targetUri: string,
624→): Promise<string> {
625→  const header = {
626→    typ: "dpop+jwt" as const,
627→    alg: "ES256" as const,
628→    jwk: {
629→      kty: keyPair.publicJwk.kty,
630→      crv: keyPair.publicJwk.crv,
631→      x: keyPair.publicJwk.x,
632→      y: keyPair.publicJwk.y,
633→    },
634→  };
635→
636→  const payload = {
637→    jti: crypto.randomUUID(),
638→    htm: method,
639→    htu: targetUri,
640→    iat: Math.floor(Date.now() / 1000),
641→  };
642→
643→  const importedKey = await jose.importJWK(
644→    await crypto.subtle.exportKey("jwk", keyPair.privateKey),
645→    "ES256",
646→  );
647→
648→  return await new jose.SignJWT(payload)
649→    .setProtectedHeader(header)
650→    .sign(importedKey);
651→}
652→
653→function base64urlBytes(bytes: Uint8Array): string {
654→  const binary = String.fromCharCode(...bytes);
655→  return btoa(binary).replace(/\+/g, "-").replace(/\//g, "_").replace(/=/g, "");
656→}
