  4→ * Extends the shared acceptance-test-kit with OAuth-specific helpers.
  5→ * All helpers use business language -- no technical jargon in function names.
  6→ *
  7→ * Driving ports:
  8→ *   POST /api/auth/intents              (intent submission with DPoP binding)
  9→ *   POST /api/auth/token                (Custom AS token endpoint)
 10→ *   POST /api/auth/bridge/exchange      (session-to-token Bridge)
 11→ *   GET  /api/auth/brain/.well-known/jwks (AS public keys)
 12→ *   All /api/mcp/* routes               (DPoP-protected Brain endpoints)
 13→ */
 14→import { RecordId, type Surreal } from "surrealdb";
 15→import * as jose from "jose";
 16→import {
 17→  generateKeyPair,
 18→  computeJwkThumbprint,
 19→  createDPoPProof,
 20→  type DPoPKeyPair as SharedDPoPKeyPair,
 21→} from "../../../app/shared/dpop";
 22→import {
 23→  setupAcceptanceSuite,
 24→  createTestUser,
 25→  fetchRaw,
 26→  type AcceptanceTestRuntime,
 27→  type TestUser as BaseTestUser,
 28→} from "../acceptance-test-kit";
 29→
 30→// Re-export shared kit essentials
 31→export {
 32→  setupAcceptanceSuite,
 33→  createTestUser,
 34→  fetchRaw,
 35→  type AcceptanceTestRuntime,
 36→  type TestUser as BaseTestUser,
 37→} from "../acceptance-test-kit";
 38→
 39→// ---------------------------------------------------------------------------
 40→// Types -- Business Language
 41→// ---------------------------------------------------------------------------
 42→
 43→export type DPoPKeyPair = SharedDPoPKeyPair;
 44→
 45→export type BrainAction = {
 46→  type: "brain_action";
 47→  action: string;
 48→  resource: string;
 49→  constraints?: Record<string, unknown>;
 50→};
 51→
 52→export type IntentSubmissionResult = {
 53→  intent_id: string;
 54→  status: string;
 55→};
 56→
 57→export type TokenResponse = {
 58→  access_token: string;
 59→  token_type: string;
 60→  expires_in: number;
 61→};
 62→
 63→export type TokenErrorResponse = {
 64→  error: string;
 65→  error_description?: string;
 66→};
 67→
 68→export type BridgeExchangeResult = {
 69→  access_token: string;
 70→  token_type: string;
 71→  expires_in: number;
 72→};
 73→
 74→export type OAuthTestRuntime = AcceptanceTestRuntime;
 75→
 76→export type TestUserWithSession = BaseTestUser & {
 77→  userId: string;
 78→};
 79→
 80→// ---------------------------------------------------------------------------
 81→// Suite Setup
 82→// ---------------------------------------------------------------------------
 83→
 84→/**
 85→ * Sets up an acceptance test suite with OAuth-specific configuration.
 86→ * Boots in-process server with isolated SurrealDB namespace.
 87→ */
 88→export function setupOAuthSuite(
 89→  suiteName: string,
 90→): () => OAuthTestRuntime {
 91→  return setupAcceptanceSuite(suiteName);
 92→}
 93→
 94→// ---------------------------------------------------------------------------
 95→// DPoP Key Pair Lifecycle Helpers
 96→// ---------------------------------------------------------------------------
 97→
 98→/**
 99→ * Generates an ES256 key pair for DPoP proof signing.
100→ * Delegates to shared generateKeyPair from app/shared/dpop.
101→ */
102→export async function generateActorKeyPair(): Promise<DPoPKeyPair> {
103→  return generateKeyPair();
104→}
105→
106→/**
107→ * Computes JWK thumbprint per RFC 7638.
108→ * Delegates to shared computeJwkThumbprint from app/shared/dpop.
109→ */
110→export async function computeKeyThumbprint(publicJwk: JsonWebKey): Promise<string> {
111→  return computeJwkThumbprint(publicJwk);
112→}
113→
114→// ---------------------------------------------------------------------------
115→// DPoP Proof Construction
116→// ---------------------------------------------------------------------------
117→
118→/**
119→ * Creates a signed DPoP proof for a specific request.
120→ * Delegates to shared createDPoPProof from app/shared/dpop.
121→ */
122→export async function createProofForRequest(
123→  keyPair: DPoPKeyPair,
124→  method: string,
125→  targetUri: string,
126→): Promise<string> {
127→  return createDPoPProof(keyPair.privateKey, keyPair.publicJwk, method, targetUri);
128→}
129→
130→/**
131→ * Creates a DPoP proof with tampered claims for error path testing.
132→ */
133→export async function createMalformedProof(
134→  keyPair: DPoPKeyPair,
135→  overrides: {
136→    typ?: string;
137→    alg?: string;
138→    htm?: string;
139→    htu?: string;
140→    iat?: number;
141→    jti?: string;
142→    omitJwk?: boolean;
143→  },
144→): Promise<string> {
145→  const header: Record<string, unknown> = {
146→    typ: overrides.typ ?? "dpop+jwt",
147→    alg: overrides.alg ?? "ES256",
148→  };
149→
150→  if (!overrides.omitJwk) {
151→    header.jwk = {
152→      kty: keyPair.publicJwk.kty,
153→      crv: keyPair.publicJwk.crv,
154→      x: keyPair.publicJwk.x,
155→      y: keyPair.publicJwk.y,
156→    };
157→  }
158→
159→  const payload = {
160→    jti: overrides.jti ?? crypto.randomUUID(),
161→    htm: overrides.htm ?? "POST",
162→    htu: overrides.htu ?? "http://127.0.0.1/test",
163→    iat: overrides.iat ?? Math.floor(Date.now() / 1000),
164→  };
165→
166→  const importedKey = await jose.importJWK(
167→    await crypto.subtle.exportKey("jwk", keyPair.privateKey),
168→    "ES256",
169→  );
170→
171→  return await new jose.SignJWT(payload)
172→    .setProtectedHeader(header as jose.JWTHeaderParameters)
173→    .sign(importedKey);
174→}
175→
176→// ---------------------------------------------------------------------------
177→// Intent Submission (Driving Port: POST /api/auth/intents)
178→// ---------------------------------------------------------------------------
179→
180→/**
181→ * Submits an intent with DPoP thumbprint binding through the driving port.
182→ * This is how agents declare what they want to do.
183→ */
184→export async function submitIntentWithDPoP(
185→  baseUrl: string,
186→  workspaceId: string,
187→  identityId: string,
188→  brainAction: BrainAction,
189→  thumbprint: string,
190→  options?: {
191→    goal?: string;
192→    reasoning?: string;
193→    priority?: number;
194→  },
195→): Promise<Response> {
196→  return fetch(`${baseUrl}/api/auth/intents`, {
197→    method: "POST",
198→    headers: { "Content-Type": "application/json" },
199→    body: JSON.stringify({
200→      workspace_id: workspaceId,
201→      identity_id: identityId,
202→      authorization_details: [brainAction],
203→      dpop_jwk_thumbprint: thumbprint,
204→      goal: options?.goal ?? "Perform authorized operation",
205→      reasoning: options?.reasoning ?? "Operation required for task completion",
206→      priority: options?.priority ?? 50,
207→    }),
208→  });
209→}
210→
211→// ---------------------------------------------------------------------------
212→// Token Acquisition (Driving Port: POST /api/auth/token)
213→// ---------------------------------------------------------------------------
214→
215→/**
216→ * Requests a DPoP-bound access token from the Custom AS.
217→ * The agent presents proof of key possession along with an authorized intent.
218→ */
219→export async function requestAccessToken(
220→  baseUrl: string,
221→  intentId: string,
222→  keyPair: DPoPKeyPair,
223→  authorizationDetails: BrainAction[],
224→): Promise<Response> {
225→  const tokenUri = `${baseUrl}/api/auth/token`;
226→  const dpopProof = await createProofForRequest(keyPair, "POST", tokenUri);
227→
228→  return fetch(tokenUri, {
229→    method: "POST",
230→    headers: {
231→      "Content-Type": "application/json",
232→      DPoP: dpopProof,
233→    },
234→    body: JSON.stringify({
235→      grant_type: "urn:brain:intent-authorization",
236→      intent_id: intentId,
237→      authorization_details: authorizationDetails,
238→    }),
239→  });
240→}
241→
242→// ---------------------------------------------------------------------------
243→// Bridge Exchange (Driving Port: POST /api/auth/bridge/exchange)
244→// ---------------------------------------------------------------------------
245→
246→/**
247→ * Exchanges a human session for a DPoP-bound token via the Bridge.
248→ * This is how dashboard users get tokens for Brain operations.
249→ */
250→export async function exchangeSessionForToken(
251→  baseUrl: string,
252→  sessionHeaders: Record<string, string>,
253→  keyPair: DPoPKeyPair,
254→  brainAction: BrainAction,
255→): Promise<Response> {
256→  const bridgeUri = `${baseUrl}/api/auth/bridge/exchange`;
257→  const dpopProof = await createProofForRequest(keyPair, "POST", bridgeUri);
258→
259→  return fetch(bridgeUri, {
260→    method: "POST",
261→    headers: {
262→      "Content-Type": "application/json",
263→      DPoP: dpopProof,
264→      ...sessionHeaders,
265→    },
266→    body: JSON.stringify({
267→      authorization_details: [brainAction],
268→    }),
269→  });
270→}
271→
272→// ---------------------------------------------------------------------------
273→// DPoP-Protected Request (Brain Resource Server)
274→// ---------------------------------------------------------------------------
275→
276→/**
277→ * Makes a DPoP-protected request to the Brain resource server.
278→ * Presents access token and fresh DPoP proof for the specific request.
279→ */
280→export async function makeDPoPProtectedRequest(
281→  baseUrl: string,
282→  path: string,
283→  accessToken: string,
284→  keyPair: DPoPKeyPair,
285→  options?: {
286→    method?: string;
287→    body?: unknown;
288→  },
289→): Promise<Response> {
290→  const method = options?.method ?? "POST";
291→  const requestUri = `${baseUrl}${path}`;
292→  const dpopProof = await createProofForRequest(keyPair, method, requestUri);
293→
294→  const headers: Record<string, string> = {
295→    Authorization: `DPoP ${accessToken}`,
296→    DPoP: dpopProof,
297→    "Content-Type": "application/json",
298→  };
299→
300→  const body = options?.body ?? {};
301→
302→  return fetch(requestUri, {
303→    method,
304→    headers,
305→    body: JSON.stringify(body),
