613→    intent: intentRecord,
614→  })) as Array<Array<{ status: string }>>;
615→
616→  throw new Error(
617→    `Intent ${intentId} did not reach ${targetStatuses.join("|")} within ${timeoutMs}ms. ` +
618→    `Current status: ${rows[0]?.[0]?.status ?? "not found"}`,
619→  );
620→}
