): Promise<RecordId<"trace", string>> {
  const id = crypto.randomUUID();
  const record = new RecordId("trace", id);

  const content: Record<string, unknown> = {
    type: params.type,
    actor: params.actor,
    workspace: params.workspace,
    created_at: new Date(),
